28	bool Deployer::RunTask(const string& task_name, TaskInitializer arg) {
29	  auto c = DeploymentTask::Require(task_name);
30	  if (!c) {
31	    LOG(ERROR) << "unknown deployment task: " << task_name;
32	    return false;
33	  }
34	  the<DeploymentTask> t(c->Create(arg));
35	  if (!t) {
36	    LOG(ERROR) << "error creating deployment task: " << task_name;
37	    return false;
38	  }
39	  return t->Run(this);
40	}
