42	bool Deployer::ScheduleTask(const string& task_name, TaskInitializer arg) {
43	  auto c = DeploymentTask::Require(task_name);
44	  if (!c) {
45	    LOG(ERROR) << "unknown deployment task: " << task_name;
46	    return false;
47	  }
48	  an<DeploymentTask> t(c->Create(arg));
49	  if (!t) {
50	    LOG(ERROR) << "error creating deployment task: " << task_name;
51	    return false;
52	  }
53	  ScheduleTask(t);
54	  return true;
55	}
56	
57	void Deployer::ScheduleTask(an<DeploymentTask> task) {
58	  std::lock_guard<std::mutex> lock(mutex_);
59	  pending_tasks_.push(task);
60	}
61	
62	an<DeploymentTask> Deployer::NextTask() {
63	  std::lock_guard<std::mutex> lock(mutex_);
64	  if (!pending_tasks_.empty()) {
65	    auto result = pending_tasks_.front();
66	    pending_tasks_.pop();
67	    return result;
68	  }
69	  // there is still chance that a task is added by another thread
70	  // right after this call... careful.
71	  return nullptr;
72	}
73	
74	bool Deployer::HasPendingTasks() {
75	  std::lock_guard<std::mutex> lock(mutex_);
76	  return !pending_tasks_.empty();
77	}
78	
79	bool Deployer::Run() {
80	  LOG(INFO) << "running deployment tasks:";
81	  message_sink_("deploy", "start");
82	  int success = 0;
83	  int failure = 0;
84	  do {
85	    while (auto task = NextTask()) {
86	      try {
87	        if (task->Run(this))
88	          ++success;
89	        else
90	          ++failure;
91	      } catch (const std::exception& ex) {
92	        ++failure;
93	        LOG(ERROR) << "Error deploying: " << ex.what();
94	      }
95	      // boost::this_thread::interruption_point();
96	    }
97	    LOG(INFO) << success + failure << " tasks ran: " << success << " success, "
98	              << failure << " failure.";
99	    message_sink_("deploy", !failure ? "success" : "failure");
100	    // new tasks could have been enqueued while we were sending the message.
101	    // before quitting, double check if there is nothing left to do.
102	  } while (HasPendingTasks());
103	  return !failure;
104	}
