106	bool Deployer::StartWork(bool maintenance_mode) {
107	  if (IsWorking()) {
108	    LOG(WARNING) << "a work thread is already running.";
109	    return false;
110	  }
111	  maintenance_mode_ = maintenance_mode;
112	  if (pending_tasks_.empty()) {
113	    return false;
114	  }
115	#ifdef RIME_NO_THREADING
116	  LOG(INFO) << "running " << pending_tasks_.size() << " tasks in main thread.";
117	  return Run();
118	#else
119	  LOG(INFO) << "starting work thread for " << pending_tasks_.size()
120	            << " tasks.";
121	  work_ = std::async(std::launch::async, [this] { Run(); });
122	  return work_.valid();
123	#endif
124	}
125	
126	bool Deployer::StartMaintenance() {
127	  return StartWork(true);
128	}
129	
130	bool Deployer::IsWorking() {
131	  if (!work_.valid())
132	    return false;
133	  auto status = work_.wait_for(std::chrono::milliseconds(0));
134	  return status != std::future_status::ready;
135	}
136	
137	bool Deployer::IsMaintenanceMode() {
138	  return maintenance_mode_ && IsWorking();
139	}
140	
141	void Deployer::JoinWorkThread() {
142	  if (work_.valid())
143	    work_.get();
144	}
145	
146	void Deployer::JoinMaintenanceThread() {
147	  JoinWorkThread();
148	}
149	
