17	Session::Session() {
18	  engine_.reset(Engine::Create());
19	  engine_->sink().connect([this](auto text) { OnCommit(text); });
20	  SessionId session_id = reinterpret_cast<SessionId>(this);
21	  engine_->message_sink().connect([session_id](auto type, auto value) {
22	    Service::instance().Notify(session_id, type, value);
23	  });
24	}
