26	bool Session::ProcessKey(const KeyEvent& key_event) {
27	  return engine_->ProcessKey(key_event);
28	}
29	
30	void Session::Activate() {
31	  last_active_time_ = time(NULL);
32	}
33	
34	void Session::ResetCommitText() {
35	  commit_text_.clear();
36	}
37	
38	bool Session::CommitComposition() {
39	  if (!engine_)
40	    return false;
41	  engine_->context()->Commit();
42	  return !commit_text_.empty();
43	}
44	
45	void Session::ClearComposition() {
46	  if (!engine_)
47	    return;
48	  engine_->context()->AbortComposition();
49	}
50	
51	void Session::ApplySchema(Schema* schema) {
52	  engine_->ApplySchema(schema);
53	}
54	
55	void Session::OnCommit(const string& commit_text) {
56	  commit_text_ += commit_text;
57	}
58	
59	Context* Session::context() const {
60	  return engine_ ? engine_->active_engine()->context() : NULL;
61	}
62	
